import type { ChartUnit } from '../../../core/types/chart-unit.js';
import { getUnitAsString } from '../../../core/utils/get-unit-as-string.js';
import { XYChart } from '../../../xy-chart/XYChartRoot.js';
import type { SeriesProps } from '../transformer-data-to-xy.js';

export const xAxisId = 'x-axis';

export const defineAxisId = (unit: ChartUnit) =>
  `y-axis-${getUnitAsString(unit)}`;

const baseSeriesProps = ({ data, unit, seriesId }: SeriesProps) => ({
  data,
  xAxisId,
  yAxisId: defineAxisId(unit),
  x0Accessor: 'start',
  x1Accessor: 'end',
  seriesIdAccessor: 'seriesId',
  nameAccessor: 'seriesName',
  key: seriesId,
});

export const renderLineSeries = (series: SeriesProps) => (
  <XYChart.LineSeries {...baseSeriesProps(series)} y0Accessor="value" />
);

export const renderAreaSeries = (series: SeriesProps) => (
  <XYChart.AreaSeries {...baseSeriesProps(series)} y1Accessor="value" />
);

export const renderBarSeries = (series: SeriesProps) => (
  <XYChart.BarSeries
    {...baseSeriesProps(series)}
    variant="stack"
    y1Accessor="value"
  />
);

export const renderBandSeries = (series: SeriesProps) => (
  <XYChart.AreaSeries
    {...baseSeriesProps(series)}
    y0Accessor="y0"
    y1Accessor="y1"
  />
);
